# Beauticare Services Platform Implementation

I'll design the implementation for a Beauticare services platform with the features you've requested, focusing on Next.js and Tailwind CSS as the technology stack. For now, we'll use JSON files for data storage with a structured approach that can be migrated to a database later.

## Project Structure

```
beauticare/
├── app/                          # Next.js app directory
│   ├── api/                      # API routes
│   ├── (auth)/                   # Authentication pages
│   ├── (business)/               # Business dashboard pages
│   ├── (client)/                 # Client dashboard pages
│   ├── (public)/                 # Public-facing pages
│   ├── layout.js                 # Root layout
│   └── page.js                   # Home page
├── components/                   # Reusable UI components
├── data/                         # JSON data files
│   ├── businesses/               # Business data
│   ├── clients/                  # Client data
│   ├── appointments/             # Appointment data
│   ├── products/                 # Product data
│   ├── reviews/                  # Reviews data
│   └── transactions/             # Payment transaction data
├── lib/                          # Utility functions
│   ├── auth.js                   # Authentication helpers
│   ├── data.js                   # Data access functions
│   └── payments.js               # Payment processing functions
├── public/                       # Static assets
└── tailwind.config.js            # Tailwind configuration
```

## Key Features Implementation

### 1. User Authentication System

```jsx
// components/auth/RegisterForm.jsx
import { useState } from 'react';
import { useRouter } from 'next/navigation';

export default function RegisterForm({ userType }) {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
    // Business-specific fields (conditionally rendered)
    businessName: '',
    businessType: '',
    businessDescription: '',
  });
  const router = useRouter();

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const response = await fetch('/api/auth/register', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ ...formData, userType }),
      });

      if (response.ok) {
        const data = await response.json();
        // Redirect to appropriate dashboard based on user type
        router.push(userType === 'business' ? '/business/dashboard' : '/client/dashboard');
      }
    } catch (error) {
      console.error('Registration failed:', error);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4 p-6 bg-white rounded-lg shadow-md">
      <h2 className="text-2xl font-bold text-center text-pink-600">
        {userType === 'business' ? 'Register Your Beauty Business' : 'Client Registration'}
      </h2>

      {/* Common fields */}
      <div>
        <label className="block text-gray-700">Full Name</label>
        <input
          type="text"
          name="name"
          value={formData.name}
          onChange={(e) => setFormData({...formData, name: e.target.value})}
          className="w-full px-4 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-pink-500"
          required
        />
      </div>

      {/* Email and password fields */}
      {/* ... */}

      {/* Business-specific fields */}
      {userType === 'business' && (
        <>
          <div>
            <label className="block text-gray-700">Business Name</label>
            <input
              type="text"
              name="businessName"
              value={formData.businessName}
              onChange={(e) => setFormData({...formData, businessName: e.target.value})}
              className="w-full px-4 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-pink-500"
              required
            />
          </div>
          {/* Other business fields */}
          {/* ... */}

          <div className="bg-yellow-50 p-4 rounded-md">
            <p className="text-sm text-gray-700">
              Business registration fee: $99.99 (Includes 3 service slots)
            </p>
          </div>
        </>
      )}

      <button
        type="submit"
        className="w-full py-2 px-4 bg-pink-600 text-white rounded-md hover:bg-pink-700 transition duration-300"
      >
        Register
      </button>
    </form>
  );
}
```

### 2. Business Profile Management

```jsx
// app/(business)/business/profile/page.jsx
'use client'
import { useState, useEffect } from 'react';
import Image from 'next/image';
import { getBusinessProfile, updateBusinessProfile } from '@/lib/data';

export default function BusinessProfile() {
  const [profile, setProfile] = useState(null);
  const [isEditing, setIsEditing] = useState(false);
  const [editedProfile, setEditedProfile] = useState({});

  useEffect(() => {
    async function loadProfile() {
      const data = await getBusinessProfile();
      setProfile(data);
      setEditedProfile(data);
    }
    loadProfile();
  }, []);

  const handleSave = async () => {
    await updateBusinessProfile(editedProfile);
    setProfile(editedProfile);
    setIsEditing(false);
  };

  if (!profile) return <div className="p-8 text-center">Loading profile...</div>;

  return (
    <div className="container mx-auto p-6">
      <div className="bg-white rounded-lg shadow-lg overflow-hidden">
        <div className="relative h-48 bg-gradient-to-r from-pink-500 to-purple-500">
          {profile.coverImage && (
            <Image 
              src={profile.coverImage} 
              alt="Business Cover" 
              layout="fill" 
              objectFit="cover" 
            />
          )}

          <div className="absolute bottom-0 left-0 transform translate-y-1/2 ml-8">
            <div className="rounded-full border-4 border-white h-32 w-32 relative overflow-hidden">
              <Image 
                src={profile.logoImage || '/default-business-logo.png'} 
                alt="Business Logo" 
                layout="fill" 
                objectFit="cover" 
              />
            </div>
          </div>
        </div>

        <div className="pt-20 px-8 pb-8">
          {isEditing ? (
            <div className="space-y-4">
              <div>
                <label className="block text-gray-700 font-medium mb-1">Business Name</label>
                <input 
                  type="text" 
                  value={editedProfile.businessName} 
                  onChange={(e) => setEditedProfile({...editedProfile, businessName: e.target.value})}
                  className="w-full border rounded-md px-4 py-2"
                />
              </div>

              <div>
                <label className="block text-gray-700 font-medium mb-1">Description</label>
                <textarea 
                  value={editedProfile.description} 
                  onChange={(e) => setEditedProfile({...editedProfile, description: e.target.value})}
                  className="w-full border rounded-md px-4 py-2 h-32"
                />
              </div>

              <div>
                <label className="block text-gray-700 font-medium mb-1">Contact Email</label>
                <input 
                  type="email" 
                  value={editedProfile.contactEmail} 
                  onChange={(e) => setEditedProfile({...editedProfile, contactEmail: e.target.value})}
                  className="w-full border rounded-md px-4 py-2"
                />
              </div>

              <div>
                <label className="block text-gray-700 font-medium mb-1">Phone Number</label>
                <input 
                  type="text" 
                  value={editedProfile.phoneNumber} 
                  onChange={(e) => setEditedProfile({...editedProfile, phoneNumber: e.target.value})}
                  className="w-full border rounded-md px-4 py-2"
                />
              </div>

              <div>
                <label className="block text-gray-700 font-medium mb-1">Address</label>
                <input 
                  type="text" 
                  value={editedProfile.address} 
                  onChange={(e) => setEditedProfile({...editedProfile, address: e.target.value})}
                  className="w-full border rounded-md px-4 py-2"
                />
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={handleSave}
                  className="px-6 py-2 bg-pink-600 text-white rounded-md hover:bg-pink-700"
                >
                  Save Changes
                </button>
                <button 
                  onClick={() => setIsEditing(false)}
                  className="px-6 py-2 border border-gray-300 rounded-md hover:bg-gray-50"
                >
                  Cancel
                </button>
              </div>
            </div>
          ) : (
            <div>
              <div className="flex justify-between items-start">
                <div>
                  <h1 className="text-3xl font-bold text-gray-900">{profile.businessName}</h1>
                  <p className="text-gray-500">{profile.businessType}</p>
                </div>
                <button 
                  onClick={() => setIsEditing(true)}
                  className="px-4 py-2 bg-pink-600 text-white rounded-md hover:bg-pink-700"
                >
                  Edit Profile
                </button>
              </div>

              <div className="mt-6">
                <h2 className="text-xl font-semibold mb-2">About</h2>
                <p className="text-gray-600">{profile.description}</p>
              </div>

              <div className="mt-6 grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-pink-50 p-4 rounded-lg">
                  <h3 className="font-medium text-pink-800">Contact Email</h3>
                  <p>{profile.contactEmail}</p>
                </div>
                <div className="bg-pink-50 p-4 rounded-lg">
                  <h3 className="font-medium text-pink-800">Phone Number</h3>
                  <p>{profile.phoneNumber}</p>
                </div>
                <div className="bg-pink-50 p-4 rounded-lg">
                  <h3 className="font-medium text-pink-800">Address</h3>
                  <p>{profile.address}</p>
                </div>
              </div>

              <div className="mt-8">
                <h2 className="text-xl font-semibold mb-4">Service Slots</h2>
                <div className="flex items-center justify-between bg-gray-50 p-4 rounded-md">
                  <div>
                    <p className="font-medium">Current Slots: {profile.serviceSlots}</p>
                    <p className="text-sm text-gray-500">Use slots to list your services</p>
                  </div>
                  <button className="px-4 py-2 bg-pink-600 text-white rounded-md hover:bg-pink-700">
                    Purchase More Slots
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
