### 3. Service Management

```jsx
// app/(business)/business/services/page.jsx
'use client'
import { useState, useEffect } from 'react';
import { getBusinessServices, addService, updateService, deleteService } from '@/lib/data';
import ServiceForm from '@/components/business/ServiceForm';

export default function BusinessServices() {
  const [services, setServices] = useState([]);
  const [isAddingService, setIsAddingService] = useState(false);
  const [editingService, setEditingService] = useState(null);
  const [businessInfo, setBusinessInfo] = useState(null);

  useEffect(() => {
    async function loadData() {
      const servicesData = await getBusinessServices();
      setServices(servicesData.services);
      setBusinessInfo(servicesData.businessInfo);
    }
    loadData();
  }, []);

  const handleAddService = async (serviceData) => {
    if (businessInfo.usedSlots >= businessInfo.totalSlots) {
      alert('You have used all your service slots. Please purchase more to add additional services.');
      return;
    }

    const newService = await addService(serviceData);
    setServices([...services, newService]);
    setIsAddingService(false);
    // Update business info with new slot usage
    setBusinessInfo({
      ...businessInfo,
      usedSlots: businessInfo.usedSlots + 1
    });
  };

  const handleUpdateService = async (serviceData) => {
    const updatedService = await updateService(serviceData);
    setServices(services.map(service => 
      service.id === updatedService.id ? updatedService : service
    ));
    setEditingService(null);
  };

  const handleDeleteService = async (serviceId) => {
    await deleteService(serviceId);
    setServices(services.filter(service => service.id !== serviceId));
    // Update business info with new slot usage
    setBusinessInfo({
      ...businessInfo,
      usedSlots: businessInfo.usedSlots - 1
    });
  };

  if (!businessInfo) return <div className="p-8 text-center">Loading...</div>;

  return (
    <div className="container mx-auto p-6">
      <div className="bg-white rounded-lg shadow-lg p-6">
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-2xl font-bold text-gray-900">Your Services</h1>
          <div className="flex items-center gap-4">
            <div className="text-sm text-gray-500">
              <span className="font-medium">{businessInfo.usedSlots}</span> of <span className="font-medium">{businessInfo.totalSlots}</span> slots used
            </div>
            <button 
              onClick={() => setIsAddingService(true)}
              className="px-4 py-2 bg-pink-600 text-white rounded-md hover:bg-pink-700 disabled:bg-gray-400"
              disabled={businessInfo.usedSlots >= businessInfo.totalSlots}
            >
              Add New Service
            </button>
          </div>
        </div>

        {businessInfo.usedSlots >= businessInfo.totalSlots && (
          <div className="mb-6 bg-yellow-50 p-4 rounded-md border border-yellow-200">
            <p className="text-yellow-800">
              You have used all your service slots. 
              <a href="/business/billing" className="text-pink-600 underline ml-1">
                Purchase more slots
              </a>
            </p>
          </div>
        )}

        {isAddingService && (
          <div className="mb-8 p-4 border border-pink-200 rounded-lg bg-pink-50">
            <h2 className="text-lg font-medium mb-3 text-pink-800">Add New Service</h2>
            <ServiceForm 
              onSubmit={handleAddService}
              onCancel={() => setIsAddingService(false)}
            />
          </div>
        )}

        {editingService && (
          <div className="mb-8 p-4 border border-pink-200 rounded-lg bg-pink-50">
            <h2 className="text-lg font-medium mb-3 text-pink-800">Edit Service</h2>
            <ServiceForm 
              initialData={editingService}
              onSubmit={handleUpdateService}
              onCancel={() => setEditingService(null)}
            />
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {services.map(service => (
            <div key={service.id} className="border rounded-lg overflow-hidden shadow-sm hover:shadow-md transition-shadow">
              {service.image && (
                <div className="h-48 relative">
                  <img 
                    src={service.image} 
                    alt={service.name} 
                    className="w-full h-full object-cover"
                  />
                </div>
              )}
              <div className="p-4">
                <h3 className="text-lg font-semibold">{service.name}</h3>
                <p className="text-pink-600 font-medium mt-1">${service.price}</p>
                <p className="text-sm text-gray-600 mt-2">{service.description}</p>
                <p className="text-sm text-gray-500 mt-2">Duration: {service.duration} min</p>

                <div className="flex justify-between mt-4 pt-3 border-t">
                  <button
                    onClick={() => setEditingService(service)}
                    className="text-blue-600 hover:text-blue-800"
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => handleDeleteService(service.id)}
                    className="text-red-600 hover:text-red-800"
                  >
                    Delete
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>

        {services.length === 0 && !isAddingService && (
          <div className="text-center py-12 text-gray-500">
            <p>You haven't added any services yet. Click "Add New Service" to get started.</p>
          </div>
        )}
      </div>
    </div>
  );
}
