### 4. Appointment Management

```jsx
// components/business/AppointmentCalendar.jsx
'use client'
import { useState, useEffect } from 'react';
import { format, startOfWeek, addDays, isSameDay, parseISO } from 'date-fns';
import { getBusinessAppointments, updateAppointmentStatus } from '@/lib/data';

export default function AppointmentCalendar() {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [appointments, setAppointments] = useState([]);
  const [selectedAppointment, setSelectedAppointment] = useState(null);

  useEffect(() => {
    async function loadAppointments() {
      const data = await getBusinessAppointments(format(currentDate, 'yyyy-MM-dd'));
      setAppointments(data);
    }
    loadAppointments();
  }, [currentDate]);

  const startDate = startOfWeek(currentDate, { weekStartsOn: 1 });
  const weekDays = [...Array(7)].map((_, i) => addDays(startDate, i));

  const handleAppointmentUpdate = async (id, status) => {
    await updateAppointmentStatus(id, status);
    setAppointments(appointments.map(apt => 
      apt.id === id ? { ...apt, status } : apt
    ));
    setSelectedAppointment(null);
  };

  return (
    <div className="bg-white rounded-lg shadow-lg overflow-hidden">
      <div className="p-4 bg-pink-600 text-white flex justify-between items-center">
        <button 
          onClick={() => setCurrentDate(prev => addDays(prev, -7))}
          className="p-2 hover:bg-pink-700 rounded"
        >
          &lt; Previous Week
        </button>
        <h2 className="text-xl font-semibold">
          Week of {format(startDate, 'MMMM d, yyyy')}
        </h2>
        <button 
          onClick={() => setCurrentDate(prev => addDays(prev, 7))}
          className="p-2 hover:bg-pink-700 rounded"
        >
          Next Week &gt;
        </button>
      </div>

      <div className="grid grid-cols-7 text-center bg-pink-100">
        {weekDays.map(day => (
          <div 
            key={day.toString()} 
            className="py-2 font-medium border-b border-pink-200"
          >
            {format(day, 'EEE')}
            <div className="text-sm font-normal">{format(day, 'MMM d')}</div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-7 gap-px bg-gray-200 min-h-[500px]">
        {weekDays.map(day => {
          const dayAppointments = appointments.filter(apt => 
            isSameDay(parseISO(apt.date), day)
          );

          return (
            <div key={day.toString()} className="bg-white p-2">
              <div className="h-full flex flex-col">
                {dayAppointments.length === 0 ? (
                  <div className="text-center text-gray-400 text-sm flex-1 flex items-center justify-center">
                    No appointments
                  </div>
                ) : (
                  <div className="space-y-2">
                    {dayAppointments.map(apt => (
                      <div 
                        key={apt.id}
                        onClick={() => setSelectedAppointment(apt)}
                        className={`p-2 rounded cursor-pointer text-sm ${
                          apt.status === 'confirmed' 
                            ? 'bg-green-100 border-l-4 border-green-500' 
                            : apt.status === 'cancelled' 
                              ? 'bg-red-100 border-l-4 border-red-500' 
                              : 'bg-yellow-100 border-l-4 border-yellow-500'
                        }`}
                      >
                        <div className="font-medium">{apt.service}</div>
                        <div>{apt.time}</div>
                        <div className="text-xs mt-1">{apt.clientName}</div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {selectedAppointment && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-lg shadow-xl max-w-md w-full p-6">
            <h3 className="text-xl font-bold mb-4">Appointment Details</h3>

            <div className="space-y-3 mb-6">
              <div>
                <span className="font-medium text-gray-700">Client:</span> {selectedAppointment.clientName}
              </div>
              <div>
                <span className="font-medium text-gray-700">Service:</span> {selectedAppointment.service}
              </div>
              <div>
                <span className="font-medium text-gray-700">Date:</span> {format(parseISO(selectedAppointment.date), 'MMMM d, yyyy')}
              </div>
              <div>
                <span className="font-medium text-gray-700">Time:</span> {selectedAppointment.time}
              </div>
              <div>
                <span className="font-medium text-gray-700">Duration:</span> {selectedAppointment.duration} minutes
              </div>
              <div>
                <span className="font-medium text-gray-700">Status:</span>{' '}
                <span className={
                  selectedAppointment.status === 'confirmed' 
                    ? 'text-green-600' 
                    : selectedAppointment.status === 'cancelled' 
                      ? 'text-red-600' 
                      : 'text-yellow-600'
                }>
                  {selectedAppointment.status.charAt(0).toUpperCase() + selectedAppointment.status.slice(1)}
                </span>
              </div>
              <div>
                <span className="font-medium text-gray-700">Notes:</span> {selectedAppointment.notes || 'None'}
              </div>
            </div>

            <div className="flex justify-between">
              <button 
                onClick={() => handleAppointmentUpdate(selectedAppointment.id, 'confirmed')}
                className="px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700"
                disabled={selectedAppointment.status === 'confirmed'}
              >
                Confirm
              </button>
              <button 
                onClick={() => handleAppointmentUpdate(selectedAppointment.id, 'cancelled')}
                className="px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700"
                disabled={selectedAppointment.status === 'cancelled'}
              >
                Cancel
              </button>
              <button 
                onClick={() => setSelectedAppointment(null)}
                className="px-4 py-2 border border-gray-300 rounded hover:bg-gray-50"
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
```

