// app/(client)/book/[businessId]/page.jsx
'use client'
import { useState, useEffect } from 'react';
import { format, addDays, startOfDay, setHours, setMinutes } from 'date-fns';
import { getBusinessDetails, getAvailableTimeSlots, createAppointment } from '@/lib/data';
import Image from 'next/image';
import { useParams, useRouter } from 'next/navigation';

export default function BookingPage() {
  const params = useParams();
  const router = useRouter();
  const businessId = params.businessId;

  const [business, setBusiness] = useState(null);
  const [services, setServices] = useState([]);
  const [selectedService, setSelectedService] = useState(null);
  const [selectedDate, setSelectedDate] = useState(startOfDay(new Date()));
  const [availableSlots, setAvailableSlots] = useState([]);
  const [selectedTime, setSelectedTime] = useState(null);
  const [notes, setNotes] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Generate next 14 days for date selection
  const dateOptions = [...Array(14)].map((_, i) => addDays(new Date(), i));

  useEffect(() => {
    async function loadBusinessData() {
      const data = await getBusinessDetails(businessId);
      setBusiness(data.business);
      setServices(data.services);
    }
    loadBusinessData();
  }, [businessId]);

  useEffect(() => {
    async function loadTimeSlots() {
      if (selectedService && selectedDate) {
        const slots = await getAvailableTimeSlots(
          businessId, 
          selectedService.id, 
          format(selectedDate, 'yyyy-MM-dd')
        );
        setAvailableSlots(slots);
        setSelectedTime(null); // Reset time when date/service changes
      }
    }
    loadTimeSlots();
  }, [businessId, selectedService, selectedDate]);

  const handleBookAppointment = async () => {
    if (!selectedService || !selectedDate || !selectedTime) {
      alert('Please select a service, date, and time.');
      return;
    }

    setIsSubmitting(true);
    try {
      await createAppointment({
        businessId,
        serviceId: selectedService.id,
        date: format(selectedDate, 'yyyy-MM-dd'),
        time: selectedTime,
        notes
      });

      router.push('/client/appointments?success=true');
    } catch (error) {
      console.error('Booking failed:', error);
      alert('There was an error booking your appointment. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (!business) return <div className="p-8 text-center">Loading...</div>;

  return (
    <div className="container mx-auto p-6">
      <div className="bg-white rounded-lg shadow-lg overflow-hidden">
        <div className="h-48 bg-gradient-to-r from-pink-500 to-purple-500 relative">
          {business.coverImage && (
            <Image 
              src={business.coverImage} 
              alt={business.name} 
              layout="fill" 
              objectFit="cover" 
            />
          )}
        </div>

        <div className="p-6">
          <div className="flex items-center mb-6">
            <div className="h-16 w-16 rounded-full overflow-hidden relative mr-4">
              <Image 
                src={business.logoImage || '/default-business-logo.png'} 
                alt={business.name} 
                layout="fill" 
                objectFit="cover" 
              />
            </div>
            <div>
              <h1 className="text-2xl font-bold">{business.name}</h1>
              <p className="text-gray-600">{business.address}</p>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div>
              <h2 className="text-xl font-semibold mb-4">Select a Service</h2>
              <div className="space-y-3">
                {services.map(service => (
                  <div 
